syntax = "proto3";

package catalog.v1;

message Product {
  reserved 4;
  reserved "sku_legacy";

  string name = 1;
  int32 quantity = 2;
  optional string description = 3;

  enum Status {
    STATUS_UNSPECIFIED = 0;
    IN_STOCK = 1;
    BACKORDERED = 2;
  }
  Status status = 5;

  repeated string tags = 6;

  oneof pricing {
    int64 price_cents = 7;
    string price_quote_id = 8;
  }

  map<string, int32> warehouse_counts = 9;

  message Dimensions {
    float width_cm = 1;
    float height_cm = 2;
  }
  Dimensions dimensions = 10;
}

