syntax = "proto3";
package tutorial;

import "google/protobuf/timestamp.proto";

option java_multiple_files = true;
option java_package = "com.example.tutorial.protos";
option java_outer_classname = "AddressBookProtos";
option csharp_namespace = "Google.Protobuf.Examples.AddressBook";
option go_package = "github.com/protocolbuffers/protobuf/examples/go/tutorialpb";

message Person {
  string name = 1;
  int32 id = 2;  // Unique ID number for this person.
  string email = 3;

  enum PhoneType {
    MOBILE = 0;
    HOME = 1;
    WORK = 2;
  }

  message PhoneNumber {
    string number = 1;
    PhoneType type = 2;
  }

  repeated PhoneNumber phones = 4;

  google.protobuf.Timestamp last_updated = 5;
}

message AddressBook {
  repeated Person people = 1;
}

// google/protobuf/wire_format_lite.h
inline uint32_t WireFormatLite::ZigZagEncode32(int32_t n) {
  return (static_cast<uint32_t>(n) << 1) ^ static_cast<uint32_t>(n >> 31);
}

type Product struct {
  Name     string `protobuf:"bytes,1,opt,name=name,proto3" json:"name,omitempty"`
  Quantity int32  `protobuf:"varint,2,opt,name=quantity,proto3" json:"quantity,omitempty"`
}

func (x *Product) GetQuantity() int32 {
  if x != nil {
    return x.Quantity
  }
  return 0
}

message Product {
  string name = 1;
  int32 quantity = 2;
}

# product_pb2.py doesn't hand-write a class -- it serializes a
# FileDescriptorProto and lets a metaclass build the real class:
Product = _reflection.GeneratedProtocolMessageType('Product', (_message.Message,), {
  'DESCRIPTOR': _PRODUCT,
  '__module__': 'product_pb2',
})

import "google/protobuf/timestamp.proto";
import "google/protobuf/duration.proto";
import "google/protobuf/field_mask.proto";

message Order {
  string order_id = 1;                       // bytes if truly opaque/binary
  int64 total_amount_minor_units = 2;         // cents -- never float/double for money
  string currency_code = 3;                   // e.g. "USD", ISO 4217

  google.protobuf.Timestamp placed_at = 4;
  google.protobuf.Duration fulfillment_sla = 5;

  enum Status {
    STATUS_UNSPECIFIED = 0;
    PENDING = 1;
    SHIPPED = 2;
    DELIVERED = 3;
    CANCELLED = 4;
  }
  Status status = 6;

  map<string, string> labels = 7;              // string/string metadata -- fine

  message LineItem {
    string sku = 1;
    int32 quantity = 2;
    optional string gift_note = 3;             // per-element presence
  }
  repeated LineItem line_items = 8;
}

message UpdateOrderRequest {
  Order order = 1;
  google.protobuf.FieldMask update_mask = 2;   // "status", "line_items" ...
}

message Product {
  // v1 shipped: name=1, quantity=2, sku_legacy=3

  string name = 1;
  int32 quantity = 2;

  reserved 3;
  reserved "sku_legacy";   // deleted; number 3 and the old name can never come back

  optional string description = 4;   // added in v2 -- old readers just skip it

  string internal_note = 5 [deprecated = true];   // still on the wire; new code shouldn't set it
}
